// ============================================================
// KILLCRITIC - DL NEXUS V3
// Workflow: 083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE
// ============================================================

const payload = $input.first().json;
const body = payload.body || {};

// --- CAMPOS OBRIGATÓRIOS ---
const camposObrigatorios = ['texto', 'approved'];
const camposFaltantes = camposObrigatorios.filter(c => !body[c]);

if (camposFaltantes.length > 0) {
  return [{
    json: {
      killcritic_aprovado: false,
      motivo: `Campos obrigatórios ausentes: ${camposFaltantes.join(', ')}`,
      workflow: '083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE',
      timestamp: new Date().toISOString()
    }
  }];
}

// --- VALIDAÇÃO DE CONTEÚDO ---
const texto = String(body.texto || '').trim();

if (texto.length < 10) {
  return [{
    json: {
      killcritic_aprovado: false,
      motivo: 'Texto da publicação muito curto (mínimo 10 caracteres).',
      workflow: '083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE',
      timestamp: new Date().toISOString()
    }
  }];
}

if (texto.length > 1500) {
  return [{
    json: {
      killcritic_aprovado: false,
      motivo: 'Texto excede 1500 caracteres (limite do Google Business Profile).',
      workflow: '083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE',
      timestamp: new Date().toISOString()
    }
  }];
}

// --- BLOCKLIST DE CONTEÚDO PROIBIDO ---
const blocklist = [
  'whatsapp.com', 'wa.me', 't.me/joinchat',
  'spam', 'fake', 'promoção ilegal'
];
const textoLower = texto.toLowerCase();
const bloqueio = blocklist.find(termo => textoLower.includes(termo));

if (bloqueio) {
  return [{
    json: {
      killcritic_aprovado: false,
      motivo: `Conteúdo bloqueado pelo KILLCRITIC: termo proibido detectado — "${bloqueio}".`,
      workflow: '083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE',
      timestamp: new Date().toISOString()
    }
  }];
}

// --- APROVAÇÃO ---
return [{
  json: {
    killcritic_aprovado: true,
    texto_validado: texto,
    url_cta: body.url_cta || 'https://dlsolucoescondominiais.com',
    motivo: 'Conteúdo aprovado pelo KILLCRITIC.',
    workflow: '083_PUBLICADOR_GOOGLE_BUSINESS_PROFILE',
    timestamp: new Date().toISOString()
  }
}];

